package com.cognizant.springlearn.controller; import com.cognizant.springlearn.model.Country; import com.cognizant.springlearn.service.CountryService; import org.springframework.http.HttpStatus; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*; import java.util.List; @RestController public class CountryController { private final CountryService countryService; public CountryController(CountryService countryService){this.countryService=countryService;} @GetMapping("/countries") public List<Country> getAllCountries(){return countryService.getAllCountries();} @PostMapping("/countries") public ResponseEntity<Country> addCountry(@RequestBody Country country){return new ResponseEntity<>(countryService.addCountry(country), HttpStatus.CREATED);} }
